Object.assign(window.search, {"doc_urls":["index.html#景山公园","index.html#命名","index.html#历史沿革","index.html#建成","index.html#衰败","index.html#复兴","index.html#地理环境","index.html#地形地貌","index.html#气候与水文","index.html#生物多样性","index.html#景区布局","index.html#重要景点","index.html#周赏亭","index.html#观妙亭","index.html#万春亭","index.html#辑芳亭","index.html#富览亭","index.html#绮望楼","index.html#寿皇殿建筑群","index.html#护国忠义庙","index.html#观德殿","index.html#文化活动","index.html#牡丹花卉展","index.html#秋实秋菊展","index.html#景山合唱节","index.html#其他看点","index.html#母子槐","index.html#二将军柏","index.html#开发与保护","index.html#相关文化","index.html#虬龙柏传说","index.html#崇祯皇帝自缢处","index.html#重要事件","index.html#价值意义","note.html#讲解提纲","note.html#景山","note.html#绮望楼","note.html#景山五方亭","note.html#寿皇殿","note.html#观德殿","note.html#崇祯自缢处","note.html#护国忠义庙","note.html#母子槐","note.html#虬龙柏"],"index":{"documentStore":{"docInfo":{"0":{"body":0,"breadcrumbs":0,"title":0},"1":{"body":0,"breadcrumbs":0,"title":0},"10":{"body":0,"breadcrumbs":0,"title":0},"11":{"body":0,"breadcrumbs":0,"title":0},"12":{"body":0,"breadcrumbs":0,"title":0},"13":{"body":0,"breadcrumbs":0,"title":0},"14":{"body":0,"breadcrumbs":0,"title":0},"15":{"body":0,"breadcrumbs":0,"title":0},"16":{"body":0,"breadcrumbs":0,"title":0},"17":{"body":0,"breadcrumbs":0,"title":0},"18":{"body":0,"breadcrumbs":0,"title":0},"19":{"body":0,"breadcrumbs":0,"title":0},"2":{"body":0,"breadcrumbs":0,"title":0},"20":{"body":0,"breadcrumbs":0,"title":0},"21":{"body":0,"breadcrumbs":0,"title":0},"22":{"body":0,"breadcrumbs":0,"title":0},"23":{"body":0,"breadcrumbs":0,"title":0},"24":{"body":0,"breadcrumbs":0,"title":0},"25":{"body":0,"breadcrumbs":0,"title":0},"26":{"body":0,"breadcrumbs":0,"title":0},"27":{"body":0,"breadcrumbs":0,"title":0},"28":{"body":1,"breadcrumbs":0,"title":0},"29":{"body":0,"breadcrumbs":0,"title":0},"3":{"body":0,"breadcrumbs":0,"title":0},"30":{"body":0,"breadcrumbs":0,"title":0},"31":{"body":0,"breadcrumbs":0,"title":0},"32":{"body":1,"breadcrumbs":0,"title":0},"33":{"body":0,"breadcrumbs":0,"title":0},"34":{"body":0,"breadcrumbs":0,"title":0},"35":{"body":1,"breadcrumbs":0,"title":0},"36":{"body":1,"breadcrumbs":0,"title":0},"37":{"body":0,"breadcrumbs":0,"title":0},"38":{"body":0,"breadcrumbs":0,"title":0},"39":{"body":0,"breadcrumbs":0,"title":0},"4":{"body":0,"breadcrumbs":0,"title":0},"40":{"body":1,"breadcrumbs":0,"title":0},"41":{"body":0,"breadcrumbs":0,"title":0},"42":{"body":0,"breadcrumbs":0,"title":0},"43":{"body":0,"breadcrumbs":0,"title":0},"5":{"body":0,"breadcrumbs":0,"title":0},"6":{"body":0,"breadcrumbs":0,"title":0},"7":{"body":0,"breadcrumbs":0,"title":0},"8":{"body":0,"breadcrumbs":0,"title":0},"9":{"body":0,"breadcrumbs":0,"title":0}},"docs":{"0":{"body":"景山公园是俯瞰故宫全景与北京中轴线的最佳观赏区，位于北京市西城区景山西街44号，坐落在北京内城南北中轴线上。南与紫禁城的神武门隔街相望，西邻北海公园，为元、明、清三代的皇宫后苑，占地23万平方米，山体海拔高度94.2米，曾是北京城中轴线上的最高点。园内保存寿皇殿、观德殿、护国忠义庙、绮望楼等古迹文物，其中寿皇殿建筑群为清代供奉御容及清帝后祭祖的重要场所，2018年修缮完成后重新开放。崇祯自缢处位于景山东坡，槐树旁矗立着“明思宗殉国处碑”与“明思宗殉国三百年纪念碑”。 景山开发于金代，元代至元四年（1267年）建大都时成为皇城御园。明永乐十八年（1420年）堆筑万岁山，清顺治十二年（1655年）更名景山。乾隆年间建造五座亭阁形成现有格局，山顶万春亭为北京中轴线制高点。光绪二十六年（1900年）遭八国联军破坏，1928年正式对外开放。新中国成立后经系统性修缮于1955年重新开放，1957年景山列为北京市第一批古建文物保护单位，2001年晋升全国重点文物保护单位，2001年晋升国家AAAA级景区，2005年获评北京市精品公园。2025年通过三维激光扫描技术完成古建数字化建模，建立石质文物数字基因库。 公园常年举办牡丹花卉展、秋菊秋实展等文化活动，2025年牡丹文化节汇集九大色系800余个品种，推出“夜赏牡丹”和VR云花展。文创产品涵盖万春亭冰箱贴、山右里咖啡等主题，设立澄茶文创茶饮空间。日常票价成人2元，活动期间调整为10元。","breadcrumbs":"概况简介 » 景山公园","id":"0","title":"景山公园"},"1":{"body":"金建国时，把开凿北海（西华潭）的淤泥堆称“青山”。1267年元忽必烈定“青山”为皇家“后苑”。明灭元后，元大内被拆的渣土淤泥又被压在“青山”之上，明成祖迁都北京，挖筒子河和太液、南海堆“青山”，形成五座错落有致的山峰，被称为“万岁山”，并大加修葺作为御园。据传明成祖朱棣在修建完皇城和紫金城后，出于防备外敌入侵的考虑，曾下令把皇宫所需使用的煤炭都堆积到万岁山下面，以保障外敌来犯时，紫禁城存储的煤足够使用。而后，景山便被称作了“煤山”。清朝，前明的残渣泥土又被堆上“青山”，清顺治皇帝在1655年改名叫景山，取意为高大的山。","breadcrumbs":"概况简介 » 命名","id":"1","title":"命名"},"10":{"body":"景山公园山上五亭横列，从东至西依此为周赏亭、观妙亭、万春亭、辑芳亭和富览亭。登上景山中峰，俯瞰京城，古都风貌尽收眼底。绮望楼位于公园前山脚下，坐北朝南，背负高山，分为上下两层，楼前建有三出陛月台，四周有汉白玉石栏杆。 路线一：南门入园—明思宗殉国处—后山腰道东侧上山—万春亭—西侧下山道—寿皇殿景区—东门出园。 路线二：西门入园—前山主路—崇祯自缢处—后山腰道东侧上山—周赏亭—观妙亭—万春亭—辑芳亭—富览亭—西侧下山道—寿皇殿景区—东门出园。 路线三：东门入园—崇祯自缢处—后山腰道东侧上山—周赏亭—观妙亭—万春亭—辑芳亭—富览亭—西侧下山道——寿皇殿景区—西门出园。","breadcrumbs":"概况简介 » 景区布局","id":"10","title":"景区布局"},"11":{"body":"","breadcrumbs":"概况简介 » 重要景点","id":"11","title":"重要景点"},"12":{"body":"周赏亭为景山五方亭之一，建于乾隆十五年（1750年），与西侧的富览亭相对而建，两座亭子的建筑形式和彩绘完全相同，为重檐圆攒尖顶，孔雀蓝琉璃瓦覆顶，紫晶色琉璃瓦剪边，亭高11.75米，建筑面积76.36平方米。周赏亭内原供奉五方佛之一的宝生佛，为铸铜镏金佛像。佛像于1900年（光绪二十六年）被八国联军劫去。","breadcrumbs":"概况简介 » 周赏亭","id":"12","title":"周赏亭"},"13":{"body":"观妙亭为景山五方亭之一，建于乾隆十五年（1750年），与西侧的缉芳亭相对而建，两座亭子建筑形式和彩绘完全相同，为重檐八角攒尖顶，翡翠绿琉璃瓦覆顶，黄琉璃瓦剪边，亭高12.05米，建筑面积90.30平方米。观妙亭内原供奉五方佛之一的阿閦佛，为铸铜镏金佛像。佛像于1900年（光绪二十六年）被八国联军劫去。","breadcrumbs":"概况简介 » 观妙亭","id":"13","title":"观妙亭"},"14":{"body":"万春亭位于景山最高处，建于乾隆十五年（1750年），是北京南北建筑中轴线的基点。被誉为北京中轴线上的制高点，京华览胜第一处。亭高15.38米，平面呈四方形，为三重檐四角攒尖顶，上檐和中檐均为九踩三昂斗拱，下檐为七踩重昂斗拱，黄琉璃瓦覆顶绿剪边，檐上有琉璃宝顶，建筑面积296.5平方米。万春亭的彩绘称为：旋子大点金龙锦枋心，这也是中国皇家等级最高的彩绘形式。万春亭内供奉着“毗卢遮那佛”，毗卢遮那佛也称为大日如来佛，是释迦牟尼佛的法身。","breadcrumbs":"概况简介 » 万春亭","id":"14","title":"万春亭"},"15":{"body":"辑芳亭为景山五方亭之一，建于乾隆十五年（1750年），与东侧的观妙亭相对而建，两座亭子的建筑形式和彩绘完全相同，为重檐八角攒尖顶，翡翠绿琉璃瓦覆顶，黄琉璃瓦剪边，亭高12.05米，建筑面积90.30平方米。缉芳亭内原供奉五方佛之一的阿弥陀佛，为铸铜镏金佛像。佛像于1900年（光绪二十六年）被八国联军劫去。","breadcrumbs":"概况简介 » 辑芳亭","id":"15","title":"辑芳亭"},"16":{"body":"富览亭建于乾隆十五年（1750年），为景山五方亭之一，与东侧的周赏亭相对而建，两座亭子的建筑形式和彩绘完全相同，为重檐圆攒尖顶，孔雀蓝琉璃瓦覆顶，紫晶色琉璃瓦剪边，亭高11.75米，建筑面积76.36平方米。富览亭内原供奉五方佛之一的不空成就佛，为铸铜镏金佛像。佛像于1900年（光绪二十六年）被八国联军劫去。","breadcrumbs":"概况简介 » 富览亭","id":"16","title":"富览亭"},"17":{"body":"绮望楼位于景山前山脚下，正对景山南门，明代这里曾建有一座五开间的大殿，称为山前殿。皇帝经常在山前殿宴请各地来京朝贺的文武官员、各部落首领及公使等，这里成为皇帝宴请宾客的宴会厅。乾隆十五年（1750年），在原建筑的基础上兴建了绮望楼。楼坐北朝南，背负高山，三楹五间，分为上下两层，歇山重檐，黄琉璃瓦顶，箍头脊，梁、架均饰有彩画。楼前建有三出陛月台，四周有汉白玉石栏杆。总建筑面积201.92平方米。取名“绮望楼”，意思是这里是登高远望、观赏美丽景致的地方。","breadcrumbs":"概况简介 » 绮望楼","id":"17","title":"绮望楼"},"18":{"body":"北京中轴线上，在明清皇家御苑景山内，矗立着一组清代皇家祭祖的庙堂，这就是寿皇殿建筑群。明代的寿皇殿建筑群曾偏居景山苑内东北隅，清乾隆十四年（1749），寿皇殿建筑群在景山的正北重建，成为清代北京城规划形成以来中轴线上唯一加建的重要建筑群。寿皇殿曾经供奉从康熙至光绪八代帝后的画像和牌位。元旦、岁暮、令节及先帝诞辰、忌辰，皇室在此恭行大礼。","breadcrumbs":"概况简介 » 寿皇殿建筑群","id":"18","title":"寿皇殿建筑群"},"19":{"body":"护国忠义庙又称关帝庙，位于观德殿建筑群东侧墙外东南角。前殿祀关帝，后殿祀真武大帝。关帝庙是前后两重院落，主殿为两连房，黄琉璃瓦覆顶，龙凤和玺彩绘。护国忠义庙是赞扬和提倡忠勇神武、丹心取义和亮节成仁的精神。据说大殿正中的匾额是康熙帝亲笔题写的“忠义”两字。","breadcrumbs":"概况简介 » 护国忠义庙","id":"19","title":"护国忠义庙"},"2":{"body":"","breadcrumbs":"概况简介 » 历史沿革","id":"2","title":"历史沿革"},"20":{"body":"观德殿建于明万历年间，是皇帝看皇子和臣子们射箭的地方。1748年，孝贤皇后去世，乾隆动用八千余工匠挪盖了新版观德殿，用以停放皇后出宫的棺木，于是观德殿就成了清代帝后的“殡宫”，即皇家殡仪馆，用作已故帝后停灵和举行祭奠仪式的场所了。同时，在旁边还加建了一座永思殿，作为皇帝在居丧期间的临时办公场所。","breadcrumbs":"概况简介 » 观德殿","id":"20","title":"观德殿"},"21":{"body":"","breadcrumbs":"概况简介 » 文化活动","id":"21","title":"文化活动"},"22":{"body":"景山公园春季牡丹花卉展已成为一个品牌，也是北京市公园管理中心推出的“一园一品”系列活动中的一项重要文化活动，已举办了十七届，随着公园牡丹、芍药品种的不断丰富，基本形成了种群各异的区域分类，主要分为九大景区：盛唐婵娟、齐鲁之春、瑶池仙子、吴越风韵、国色天香、花舞弄影、锦贺东瀛、艳若蒸霞、绮望春色。","breadcrumbs":"概况简介 » 牡丹花卉展","id":"22","title":"牡丹花卉展"},"23":{"body":"景山公园每年都会举行一次秋菊、秋实展。为了丰富展览内容，公园每年都引进一些菊花新、奇品种，如直径4米的大立菊、高3.5米的塔菊、长4米的大悬崖菊和采用嫁接手法用菊花扎成的“龙凤呈祥”、“二龙戏珠”、“孔雀开屏”的艺菊，品种菊有独本菊、多头菊等。","breadcrumbs":"概况简介 » 秋实秋菊展","id":"23","title":"秋实秋菊展"},"24":{"body":"景山合唱节是北京西城区的一项传统合唱比赛，从2004年开始，历经19年的发展，合唱节吸引了北京市多个合唱团参与，他们以歌声传递友谊，唱响未来，给观众留下了深刻的印象。景山合唱节由西城区文化和旅游、西城区文化馆主办。","breadcrumbs":"概况简介 » 景山合唱节","id":"24","title":"景山合唱节"},"25":{"body":"","breadcrumbs":"概况简介 » 其他看点","id":"25","title":"其他看点"},"26":{"body":"在景山公园偏东北的位置，永思殿前殿的西侧长有一棵老槐树，这株槐树是景山公园里树龄较长的古树，胸径约有2米，胸围6米有余，冠高约20米。从远处看这株古槐，树干高耸挺拔，枝干舒展昂扬，叶茂荫茸，生机勃发。但是走到近处观看，就会发现这株古槐的主干早已朽空，西南侧的树干也脱皮迸裂，整个主干只剩下很薄的木栓层和苍老的树皮支撑着树冠并维持着生机。 不知何时，在朽空的树干中又生出了一株小槐树，弯弯曲曲地沿着树洞向上生长到近10米高。天长日久，小树的胸径长到一尺多，树冠伸出了树洞，外皮与大树的枝干也慢慢地长在了一起。这株古槐怀中长出小槐树，俗称“母子槐”。","breadcrumbs":"概况简介 » 母子槐","id":"26","title":"母子槐"},"27":{"body":"在景山公园牡丹园的东侧有两棵树形苍劲挺拔、高大威武的古柏，就是景山有名的“二将军柏”。历史上，位于观德殿前面的这片牡丹地，原本是明清时期帝王的演武场。观徳殿建筑群始建于明代，皇帝在这里欣赏儿臣们的骑射表演，皇帝演武时所骑的御用马匹就拴在这两棵柏树东面的御马圈中。","breadcrumbs":"概况简介 » 二将军柏","id":"27","title":"二将军柏"},"28":{"body":"北京市中轴线已列入世界文化遗产的备选名单，“寿皇殿古建筑群”是中轴线上的第二大建筑群，根据北京市 “十二五”规划提出重构历史文化魅力走廊、系统规划实施魅力中轴线工程的要求，2014年11月3日起“寿皇殿建筑群修缮工程——外院南墙修缮”全面施工。“寿皇殿建筑群修缮工程”是中轴线申遗重点工程，遵循景山公园《景山公园总体规划》、《景山公园文物保护规划》。该工程将对寿皇殿建筑群进行修缮。 2015年10月，景山公园的寿皇殿经过一年多的勘察设计，寿皇殿文物建筑群修缮工程的设计审批工作已经完成，预计投入8000多万元进行维修。 近年来，已完成钟楼及钟架、鼓楼擎檐柱，景山兴庆阁，太庙享殿东、西配殿和寝殿东西配殿、世庙北墙，社稷坛中山堂、宰牲亭、坛墙和坛门，正阳门箭楼等文物古建的修缮工程。 2018年年底，经过4年修缮，景山公园寿皇殿建筑群再次向公众开放。作为中轴线上第二大建筑群，也是景山古建筑的核心区域，寿皇殿的开放，使景山公园完整地展现在公众面前。据介绍，寿皇殿修缮过程中，除了研究文献资料、图纸、图档，一批20世纪初的老照片成了重要参考，修缮人员详细比对每一张照片和历史资料，尽力还原，做到每处修缮都有据可循。比如殿外月台地面的铺砖，根据历史照片显示，是用二城样砖，按城砖陡板斜墁的方式铺装，修缮中遵循此法，实现了“磨砖对缝”严丝合缝。 2020年10月，正阳门箭楼修缮启动，对象包括箭楼城台、浮雕、窗眉、室内木构件油饰、屋面等。修缮中，每一处都坚持原材料、原形制、原工艺、原做法，最大限度保留历史信息。 2023年9月，景山公园持续加强古树养护管理。","breadcrumbs":"概况简介 » 开发与保护","id":"28","title":"开发与保护"},"29":{"body":"","breadcrumbs":"概况简介 » 相关文化","id":"29","title":"相关文化"},"3":{"body":"景山草创于公元12世纪的金大定年间，金国在附近建太宁宫，凿西华潭（今北海），在此堆成小丘，山上建瑶广楼，时为金中都十二景之一。13世纪中叶，元世祖忽必烈建大都，将此处辟为专供皇帝赏乐的“后苑”，将原有小丘改称“青山”。 明永乐十八年（1420年）在修建北京城时用拆除元代宫殿的渣土和挖掘故宫护城河的泥土在元代延春阁的基础上堆起一座土山，高45.7米，取名“万岁山”，又称“镇山”，意为“镇压元代之王气”之意。山上种植松柏，山下种植果树，故当时又称“百果园”。园内陆续修建了富丽辉煌的寿皇殿建筑群，包括寿皇门、寿皇殿、东西配殿、碑亭等。主要建筑还配有永思殿、观德殿等相对独立的建筑体系。 清顺治十二年（1655年），“万岁山”改名为“景山”。乾隆十四年（1749年）原在景山东北部的寿皇殿移建于现址。乾隆十六年（1751年），景山山顶建造了五座造型优美、风格各异的亭子，自东向西分别为“周赏亭”“观妙亭”“万春亭”“辑芳亭”和“富揽亭”，每个亭内供奉一尊铜佛，称“五方佛”。","breadcrumbs":"概况简介 » 建成","id":"3","title":"建成"},"30":{"body":"在明朝嘉靖年间，宫中有一只毛色特别、眉间雪白的狮子猫，名为“霜眉”。此猫颇通人性，能准确领会并响应皇帝的召唤，陪伴皇上左右，甚至在皇上休息时也不离半步，因而深受宠爱。猫死后，嘉靖帝哀悼，命翰林院侍读袁炜撰写悼词，其中有“化狮为龙”之句，得到皇帝的赞赏。遵照嘉靖帝的旨意，猫被葬于万岁山北的一棵古树旁，并立碑“虬龙冢”以作纪念。","breadcrumbs":"概况简介 » 虬龙柏传说","id":"30","title":"虬龙柏传说"},"31":{"body":"在景山东坡的山石之上，有一棵歪脖古槐，明朝最后一个皇帝朱由检就是在这里自缢的。 明代崇祯十七年（1644年），李自成率领40万农民起义军进攻到北京，夏历三月十九日，崇祯皇帝见大势已去，“因命进酒，连酌数觥。”先派人遣送太子出城，然后逼迫皇后及妃嫔们自缢，又砍杀了两位公主，最后从紫禁城的神武门逃出爬到景山，在国破家亡的绝望之中，崇祯皇帝咬破手指，在衣襟上写下了遗诏：“朕凉德藐躬，上干天咎，致贼直逼京师，皆诸臣误朕。朕死，无面目祖宗，自去冠冕，以发覆面，任贼分裂，勿伤百姓一人。”就在景山东坡的歪脖老槐树下自缢身亡，时年33岁。当时，崇祯皇帝的侍臣秉笔太监王承恩也自缢在对面的海棠树下。","breadcrumbs":"概况简介 » 崇祯皇帝自缢处","id":"31","title":"崇祯皇帝自缢处"},"32":{"body":"2001年被列为全国文物保护单位，国家AAAA级景区，2005年被评为北京市精品公园。 2020年11月，入选首届北京网红打卡地上榜名单（共100家）。","breadcrumbs":"概况简介 » 重要事件","id":"32","title":"重要事件"},"33":{"body":"景山公园曾是清帝后祭祖追思的重要场所，保存着寿皇殿、观德殿、护国忠义庙、绮望楼等古迹文物，散发着浓厚的根祖气息，是传承和发扬中华孝道文化的胜地。 开放后的景山公园不仅具有休闲娱乐的属性，更兼具文化教育、政治宣传、军事高地的职能。在承担文化教育职能方面，景山公园为文化宣传提供了平台，成为举行社会活动和宣传新思想的场所。同时，景山公园的人文建筑也发挥着文化教育的载体功能。除了文化宣传外，景山公园也是世人表达政治诉求的舞台，兼具政治宣传的职能。同时，景山公园也因景山的特殊高度和地理位置，在军事上发挥着其特有的职能。近代景山公园的属性变迁和职能转换，既是近代中国社会转型的具体体现，又是近代社会思想解放潮流的真实映照，但在半殖民地半封建社会的中国，景山公园的职能变迁掩盖不了破败荒凉的现实遭遇。中华人民共和国的成立，结束了近代以来中国任人欺侮的历史，人民当家做主成为国家的主人，景山公园也迎来了新生——成为人民的公园，承担起为人民服务的职能。","breadcrumbs":"概况简介 » 价值意义","id":"33","title":"价值意义"},"34":{"body":"","breadcrumbs":"讲解提纲 » 讲解提纲","id":"34","title":"讲解提纲"},"35":{"body":"景山又称煤山、镇山、万岁山、玄武山。 原本是一座带有风水性质的山，所以称为镇山、玄武山。 金大定十九年（1179年），金世宗在辽瑶屿行宫的基础上建太宁宫，并开凿了西华潭（今北海），淤泥堆成小丘。 13世纪中叶，元世祖忽必烈建大都，将此处辟为专供皇帝赏乐的“后苑”，将原有小丘改称“青山”。 明永乐十八年（1420年），在修建北京城时，用拆除元代宫殿的渣土和挖掘故宫护城河的泥土，在元代延春阁的基础上堆起一座土山，取名“万岁山”，又称“镇山”。 清顺治十二年（1655年），“万岁山”改名为“景山”。","breadcrumbs":"讲解提纲 » 景山","id":"35","title":"景山"},"36":{"body":"明代建有一座五开间的大殿，称为山前殿。皇帝经常在山前殿宴请各地来京朝贺的文武官员、各部落首领及公使等，这里成为皇帝宴请宾客的宴会厅。 清乾隆十五年（1750年），在原建筑的基础上兴建了绮望楼。","breadcrumbs":"讲解提纲 » 绮望楼","id":"36","title":"绮望楼"},"37":{"body":"乾隆十六年（1751年），景山山顶建造了五座造型优美、风格各异的亭子。 周赏亭 观妙亭 万春亭 大日如来佛 辑芳亭 富览亭","breadcrumbs":"讲解提纲 » 景山五方亭","id":"37","title":"景山五方亭"},"38":{"body":"明代的寿皇殿建筑群曾偏居景山苑内东北隅。 清乾隆十四年（1749），寿皇殿建筑群在景山的正北重建，成为清代北京城规划形成以来中轴线上加建的重要建筑群。 寿皇殿曾经供奉从康熙至光绪八代帝后的画像和牌位。 元旦、岁暮、令节及先帝诞辰、忌辰，皇室在此恭行大礼。","breadcrumbs":"讲解提纲 » 寿皇殿","id":"38","title":"寿皇殿"},"39":{"body":"孝贤皇后 永恩殿、观德殿位于寿皇殿东，明代时是帝王的习射之所。 清代乾隆起，便改为停放帝后的灵柩之处。","breadcrumbs":"讲解提纲 » 观德殿","id":"39","title":"观德殿"},"4":{"body":"光绪二十六年（1900年），八国联军入侵北京后，驻军景山，园内古建筑遭破坏，许多文物被劫走，山上五亭内的铜佛，除万春亭的毗卢遮那佛外，其他四尊均被劫走。此后，景山一度荒芜，处于年久失修的状态。但作为封建皇室御用之地，除皇室成员外，其他文武百官不经准许仍不得擅自入内。辛亥革命后，封建帝制被废除，但根据《清室退位优待条件》，景山仍归属前清皇室使用。1924年冯玉祥发动“北京政变”，将末代皇帝溥仪逐出皇宫，作为清室财产的景山由清室善后委员会接管。","breadcrumbs":"概况简介 » 衰败","id":"4","title":"衰败"},"40":{"body":"原树早已枯死伐除，现存槐树为重新栽种的，并挂有说明牌。 在景山东坡的歪脖老槐树下自缢身亡，时年33岁。 遗诏：朕凉德藐躬，上干天咎，致贼直逼京师，皆诸臣误朕。朕死，无面目祖宗，自去冠冕，以发覆面，任贼分裂，勿伤百姓一人。 御前太监王承恩，自缢在对面的海棠树下。","breadcrumbs":"讲解提纲 » 崇祯自缢处","id":"40","title":"崇祯自缢处"},"41":{"body":"二将军柏","breadcrumbs":"讲解提纲 » 护国忠义庙","id":"41","title":"护国忠义庙"},"42":{"body":"","breadcrumbs":"讲解提纲 » 母子槐","id":"42","title":"母子槐"},"43":{"body":"明朝嘉靖年间，宫中有一只毛色特别、眉间雪白的狮子猫，名为“霜眉”。 猫死后，嘉靖帝哀悼，命翰林院侍读袁炜撰写悼词，其中有“化狮为龙”之句。 遵照嘉靖帝的旨意，猫被葬于万岁山北的一棵古树旁，并立碑“虬龙冢”以作纪念。","breadcrumbs":"讲解提纲 » 虬龙柏","id":"43","title":"虬龙柏"},"5":{"body":"1925年10月后，归属故宫博物院管理。于1928年，景山作为公园对外正式开放。 中华人民共和国成立后，国家对景山公园内的重点建筑多次进行了修缮，铺装了山道和园路，1955年重新开放。1957年北京市人民政府将景山公园列为第一批古建文物保护单位。1998年，公园复原了万春亭内的毗卢遮那佛(大日如来佛)，受到中外游客的称赞。2001年，景山公园被列为全国重点文物保护单位、国家AAAA级景区。2003年，成立景山公园管理处。2005年被评为北京市精品公园。 2025年12月16日，北京中轴线世界遗产碑（景山）正式亮相景山公园南门承载着六百年历史的“万岁门”前，与原有的“全国重点文物保护单位”标志石碑并肩而立。","breadcrumbs":"概况简介 » 复兴","id":"5","title":"复兴"},"6":{"body":"","breadcrumbs":"概况简介 » 地理环境","id":"6","title":"地理环境"},"7":{"body":"景山公园位于北京市西城区景山西街44号，座落于北京城南北中轴线上，南依故宫，西靠北海，北与鼓楼遥遥相望。公园占地面积23万平方米，山体海拔高度94.2米，是北京城中轴线上最高的山峰，是俯瞰故宫全景与北京中轴线的最佳观赏区。处于平原区中的“北京缓倾斜冲积平原区”内，地貌单元由古永定河、清水河、温榆河联合冲积而成，全区处于该地貌单元的中部。地面高程30至50米之间，由西北向东南缓倾，平均坡度为1.2‰至1.3‰。","breadcrumbs":"概况简介 » 地形地貌","id":"7","title":"地形地貌"},"8":{"body":"景山公园属暖温带半湿润半干旱季风气候，年平均气温为9～11℃。四季分明，冬季最长，夏季次之，春、秋短促。景山位于北京地区少雨区，年平均降水量在400mm-500mm之间，年降雨量少，且相对集中在夏季（占全年降水量74%）。","breadcrumbs":"概况简介 » 气候与水文","id":"8","title":"气候与水文"},"9":{"body":"公园内种植着大量古树名木，公园后山东侧的虬龙柏、永思殿前的母子槐、关帝庙前的二将军柏是公园著名的人文景观。园内还种植着大量牡丹、芍药，景山牡丹种植历史最早可追溯至元代，园内汇集了名优牡丹500余种，春季牡丹盛开，松柏碧绿，交相辉映，成为京城著名景观。","breadcrumbs":"概况简介 » 生物多样性","id":"9","title":"生物多样性"}},"length":44,"save":true},"fields":["title","body","breadcrumbs"],"index":{"body":{"root":{"1":{"6":{"5":{"5":{"df":1,"docs":{"35":{"tf":1.0}}},"df":0,"docs":{}},"df":0,"docs":{}},"7":{"5":{"0":{"df":1,"docs":{"36":{"tf":1.0}}},"df":0,"docs":{}},"df":0,"docs":{}},"df":0,"docs":{}},"2":{"0":{"2":{"0":{"df":0,"docs":{},"年":{"1":{"1":{"df":0,"docs":{},"月":{"df":0,"docs":{},"，":{"df":0,"docs":{},"入":{"df":0,"docs":{},"选":{"df":0,"docs":{},"首":{"df":0,"docs":{},"届":{"df":0,"docs":{},"北":{"df":0,"docs":{},"京":{"df":0,"docs":{},"网":{"df":0,"docs":{},"红":{"df":0,"docs":{},"打":{"df":0,"docs":{},"卡":{"df":0,"docs":{},"地":{"df":0,"docs":{},"上":{"df":0,"docs":{},"榜":{"df":0,"docs":{},"名":{"df":0,"docs":{},"单":{"df":0,"docs":{},"（":{"df":0,"docs":{},"共":{"1":{"0":{"0":{"df":1,"docs":{"32":{"tf":1.0}}},"df":0,"docs":{}},"df":0,"docs":{}},"df":0,"docs":{}}}}}}}}}}}}}}}}}}}}},"df":0,"docs":{}},"df":0,"docs":{}}},"3":{"df":0,"docs":{},"年":{"9":{"df":1,"docs":{"28":{"tf":1.0}}},"df":0,"docs":{}}},"df":0,"docs":{}},"df":0,"docs":{}},"df":0,"docs":{}},"3":{"3":{"df":1,"docs":{"40":{"tf":1.0}}},"df":0,"docs":{}},"df":0,"docs":{}}},"breadcrumbs":{"root":{"1":{"6":{"5":{"5":{"df":1,"docs":{"35":{"tf":1.0}}},"df":0,"docs":{}},"df":0,"docs":{}},"7":{"5":{"0":{"df":1,"docs":{"36":{"tf":1.0}}},"df":0,"docs":{}},"df":0,"docs":{}},"df":0,"docs":{}},"2":{"0":{"2":{"0":{"df":0,"docs":{},"年":{"1":{"1":{"df":0,"docs":{},"月":{"df":0,"docs":{},"，":{"df":0,"docs":{},"入":{"df":0,"docs":{},"选":{"df":0,"docs":{},"首":{"df":0,"docs":{},"届":{"df":0,"docs":{},"北":{"df":0,"docs":{},"京":{"df":0,"docs":{},"网":{"df":0,"docs":{},"红":{"df":0,"docs":{},"打":{"df":0,"docs":{},"卡":{"df":0,"docs":{},"地":{"df":0,"docs":{},"上":{"df":0,"docs":{},"榜":{"df":0,"docs":{},"名":{"df":0,"docs":{},"单":{"df":0,"docs":{},"（":{"df":0,"docs":{},"共":{"1":{"0":{"0":{"df":1,"docs":{"32":{"tf":1.0}}},"df":0,"docs":{}},"df":0,"docs":{}},"df":0,"docs":{}}}}}}}}}}}}}}}}}}}}},"df":0,"docs":{}},"df":0,"docs":{}}},"3":{"df":0,"docs":{},"年":{"9":{"df":1,"docs":{"28":{"tf":1.0}}},"df":0,"docs":{}}},"df":0,"docs":{}},"df":0,"docs":{}},"df":0,"docs":{}},"3":{"3":{"df":1,"docs":{"40":{"tf":1.0}}},"df":0,"docs":{}},"df":0,"docs":{}}},"title":{"root":{"df":0,"docs":{}}}},"lang":"English","pipeline":["trimmer","stopWordFilter","stemmer"],"ref":"id","version":"0.9.5"},"results_options":{"limit_results":30,"teaser_word_count":30},"search_options":{"bool":"OR","expand":true,"fields":{"body":{"boost":1},"breadcrumbs":{"boost":1},"title":{"boost":2}}}});